      "keystrokes": "cat > /app/solve_sudoku.py << 'PY'
import sys

def read_grid(path):
    with open(path, 'r') as f:
        lines = [line.strip() for line in f if line.strip()]
    if len(lines) != 9:
        print('Error: input must have exactly 9 non-empty lines', file=sys.stderr)
        sys.exit(1)
    grid = []
    for i, line in enumerate(lines):
        parts = line.split()
        if len(parts) != 9:
            print(f'Error: line {i+1} must have exactly 9 integers', file=sys.stderr)
            sys.exit(1)
        try:
            row = [int(x) for x in parts]
        except ValueError:
            print(f'Error: line {i+1} contains non-integer values', file=sys.stderr)
            sys.exit(1)
        grid.append(row)
    return grid

def is_valid(grid, r, c, val):
    # Row and column
    if any(grid[r][k] == val for k in range(9)):
        return False
    if any(grid[k][c] == val for k in range(9)):
        return False
    # 3x3 box
    br = (r // 3) * 3
    bc = (c // 3) * 3
    for i in range(3):
        for j in range(3):
            if grid[br + i][bc + j] == val:
                return False
    return True

def find_empty(grid):
    for i in range(9):
        for j in range(9):
            if grid[i][j] == 0:
                return i, j
    return None

def solve(grid):
    pos = find_empty(grid)
    if not pos:
        return True
    r, c = pos
    for val in range(1, 10):
        if is_valid(grid, r, c, val):
            grid[r][c] = val
            if solve(grid):
                return True
            grid[r][c] = 0
    return False

def write_grid(grid, path):
    with open(path, 'w') as f:
        for row in grid:
            f.write(' '.join(str(x) for x in row) + '\n')

def main():
    if len(sys.argv) < 3:
        print('Usage: solve_sudoku.py input.txt output.txt', file=sys.stderr)
        sys.exit(1)
    inp = sys.argv[1]
    out = sys.argv[2]
    grid = read_grid(inp)
    if not solve(grid):
        print('No solution found', file=sys.stderr)
        sys.exit(2)
    write_grid(grid, out)

if __name__ == '__main__':
    main()
